import { chromium } from 'playwright';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

async function captureScreenshots() {
  const browser = await chromium.launch();
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 }
  });

  try {
    // Light mode screenshot
    console.log('Capturing light mode screenshot...');
    const lightPage = await context.newPage();
    await lightPage.goto('http://localhost:6006/?path=/story/sdui-demo-voucher--form');
    await lightPage.waitForTimeout(3000);
    await lightPage.screenshot({
      path: join(__dirname, 'editor-current-state.png'),
      fullPage: true
    });
    console.log('✓ Light mode screenshot saved to editor-current-state.png');
    await lightPage.close();

    // Dark mode screenshot
    console.log('Capturing dark mode screenshot...');
    const darkPage = await context.newPage();
    await darkPage.goto('http://localhost:6006/?path=/story/sdui-demo-voucher--form&globals=theme:dark');
    await darkPage.waitForTimeout(3000);
    await darkPage.screenshot({
      path: join(__dirname, 'editor-dark-current.png'),
      fullPage: true
    });
    console.log('✓ Dark mode screenshot saved to editor-dark-current.png');
    await darkPage.close();

  } catch (error) {
    console.error('Error capturing screenshots:', error);
    throw error;
  } finally {
    await browser.close();
  }
}

captureScreenshots();

