 24→
 25→interface ProductToggleProps {
 26→  selected: Product;
 27→  onSelect: (p: Product) => void;
 28→}
 29→
 30→function ProductToggle({ selected, onSelect }: ProductToggleProps) {
 31→  return (
 32→    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
 33→      {PRODUCTS.map(p => (
 34→        <Pressable
 35→          key={p}
 36→          onPress={() => onSelect(p)}
 37→          style={{
 38→            paddingHorizontal: 16,
 39→            paddingVertical: 8,
 40→            borderRadius: 20,
 41→            backgroundColor: selected === p ? '#6B2FBE' : '#E8E0F0',
 42→          }}
 43→        >
 44→          <Text
