 47→          >
 48→            {p}
 49→          </Text>
 50→        </Pressable>
 51→      ))}
 52→    </View>
 53→  );
 54→}
 55→
 56→interface ScreenPair {
 57→  Abastecimento: SDUIScreen;
 58→  Estacionamento: SDUIScreen;
 59→}
 60→
 61→const SCREEN_PAIRS: Record<string, ScreenPair> = {
 62→  Form: {
 63→    Abastecimento: voucherFormAbastecimento,
 64→    Estacionamento: voucherFormEstacionamento,
 65→  },
 66→  Summary: {
 67→    Abastecimento: voucherSummaryAbastecimento,
 68→    Estacionamento: voucherSummaryEstacionamento,
 69→  },
 70→  Conclusion: {
 71→    Abastecimento: voucherConclusionAbastecimento,
 72→    Estacionamento: voucherConclusionEstacionamento,
 73→  },
 74→  Rules: {
 75→    Abastecimento: voucherRulesAbastecimento,
 76→    Estacionamento: voucherRulesEstacionamento,
 77→  },
 78→};
 79→
 80→const SCREEN_NAMES = Object.keys(SCREEN_PAIRS);
 81→
 82→function ScreenWithToggle({ pair, title }: { pair: ScreenPair; title: string }) {
 83→  const [product, setProduct] = useState<Product>('Abastecimento');
 84→  const screen = useSDUIJsonEditor(pair[product]);
 85→
 86→  return (
 87→    <View style={{ padding: 24, maxWidth: 420 }}>
 88→      <Text type="headingMDL" mb="nano">
 89→        {title}
 90→      </Text>
 91→      <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
 92→        Toggle product or edit the JSON Editor panel below to see live changes.
 93→      </Text>
 94→
 95→      <ProductToggle selected={product} onSelect={setProduct} />
 96→
 97→      <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
 98→        <ScreenRenderer screen={screen} />
 99→      </Box>
100→    </View>
101→  );
102→}
103→
104→function VoucherFormDemo() {
105→  return <ScreenWithToggle pair={SCREEN_PAIRS.Form} title="Voucher Form" />;
106→}
107→
108→function VoucherSummaryDemo() {
109→  return (
110→    <ScreenWithToggle pair={SCREEN_PAIRS.Summary} title="Voucher Summary" />
111→  );
112→}
113→
114→function VoucherConclusionDemo() {
115→  return (
116→    <ScreenWithToggle
117→      pair={SCREEN_PAIRS.Conclusion}
118→      title="Voucher Conclusion"
119→    />
120→  );
121→}
122→
123→function VoucherRulesDemo() {
124→  return <ScreenWithToggle pair={SCREEN_PAIRS.Rules} title="Voucher Rules" />;
125→}
126→
127→function FullFlowDemo() {
128→  const [product, setProduct] = useState<Product>('Abastecimento');
129→  const [step, setStep] = useState(0);
130→  const currentName = SCREEN_NAMES[step];
131→  const screen = useSDUIJsonEditor(SCREEN_PAIRS[currentName][product]);
132→
133→  return (
134→    <ScrollView style={{ flex: 1 }}>
135→      <View style={{ padding: 24, maxWidth: 420 }}>
136→        <Text type="headingMDL" mb="nano">
137→          SDUI Spike — Full Voucher Flow
138→        </Text>
139→        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
140→          Same ScreenRenderer, same adapters — only the JSON changes.
141→        </Text>
142→
143→        <ProductToggle selected={product} onSelect={setProduct} />
144→
145→        <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
146→          {SCREEN_NAMES.map((name, idx) => (
147→            <Pressable
148→              key={name}
149→              onPress={() => setStep(idx)}
150→              style={{
151→                paddingHorizontal: 12,
152→                paddingVertical: 6,
153→                borderRadius: 8,
154→                backgroundColor: step === idx ? '#1A1A2E' : '#F0F0F5',
155→              }}
156→            >
157→              <Text
158→                type={step === idx ? 'paragraphMDM' : 'paragraphMD'}
159→                color={step === idx ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_03'}
160→              >
161→                {`${idx + 1}. ${name}`}
162→              </Text>
163→            </Pressable>
164→          ))}
165→        </View>
166→
167→        <SeparatorHorizontal
168→          mb="smaller"
169→          bgColor="BRAND_COMPLEMENT_02"
170→          height={1}
171→          width="100%"
172→        />
173→
174→        <Text type="subtitleXXL" mb="nano">
175→          {currentName} — {product}
176→        </Text>
177→
178→        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
179→          <ScreenRenderer screen={screen} />
180→        </Box>
181→      </View>
182→    </ScrollView>
183→  );
184→}
185→
186→const meta: Meta<typeof FullFlowDemo> = {
187→  title: 'SDUI/VoucherDemo',
188→  component: FullFlowDemo,
189→};
190→
191→export default meta;
192→
193→type Story = StoryObj<typeof meta>;
194→
195→export const Form: Story = {
196→  render: () => <VoucherFormDemo />,
197→};
198→
199→export const Summary: Story = {
200→  render: () => <VoucherSummaryDemo />,
201→};
202→
