204→  render: () => <VoucherConclusionDemo />,
205→};
206→
207→export const Rules: Story = {
208→  render: () => <VoucherRulesDemo />,
209→};
210→
211→export const FullFlow: Story = {
212→  render: () => <FullFlowDemo />,
213→};
